/**
 * @suppress
 */
public object FfiConverterTypeSdrBridge: FfiConverter<SdrBridge, Pointer> {

    override fun lower(value: SdrBridge): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): SdrBridge {
        return SdrBridge(value)
    }

    override fun read(buf: ByteBuffer): SdrBridge {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: SdrBridge) = 8UL

    override fun write(value: SdrBridge, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



data class BridgeDxSpot (
    var `callsign`: kotlin.String, 
    var `frequencyHz`: kotlin.ULong, 
    var `mode`: kotlin.String, 
    var `spotter`: kotlin.String, 
