}

/**
 * @suppress
 */
public object FfiConverterTypeBridgeDxSpot: FfiConverterRustBuffer<BridgeDxSpot> {
    override fun read(buf: ByteBuffer): BridgeDxSpot {
        return BridgeDxSpot(
            FfiConverterString.read(buf),
            FfiConverterULong.read(buf),
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
            FfiConverterString.read(buf),
            FfiConverterUShort.read(buf),
            FfiConverterUShort.read(buf),
        )
    }

    override fun allocationSize(value: BridgeDxSpot) = (
            FfiConverterString.allocationSize(value.`callsign`) +
            FfiConverterULong.allocationSize(value.`frequencyHz`) +
            FfiConverterString.allocationSize(value.`mode`) +
            FfiConverterString.allocationSize(value.`spotter`) +
            FfiConverterString.allocationSize(value.`comment`) +
            FfiConverterUShort.allocationSize(value.`ageSeconds`) +
            FfiConverterUShort.allocationSize(value.`expirySeconds`)
    )

    override fun write(value: BridgeDxSpot, buf: ByteBuffer) {
            FfiConverterString.write(value.`callsign`, buf)
            FfiConverterULong.write(value.`frequencyHz`, buf)
            FfiConverterString.write(value.`mode`, buf)
            FfiConverterString.write(value.`spotter`, buf)
            FfiConverterString.write(value.`comment`, buf)
            FfiConverterUShort.write(value.`ageSeconds`, buf)
            FfiConverterUShort.write(value.`expirySeconds`, buf)
    }
}



